} from "@lotto/shared";
import { explainWithAgent } from "./agentClient.js";

/**
 * Produces lottery number recommendations for the requested draw, enriched with
 * LLM-authored explanations when the agent is reachable.
 *
 * Freshness branching: unless `skipLiveSync` is set, the latest draws are pulled
 * from the provider via {@link syncDrawsBeforeServing} and the outcome is
 * classified into `freshness`. If the sync throws, freshness falls back to
 * `last-good` — the stored `latestDrawNo` is reported alongside a `syncErrorKind`
 * derived from the error (the {@link DrawBackfillError} code, the error name, or
 * `"UnknownError"`) instead of propagating the failure. When `skipLiveSync` is
 * set, no provider call is made and freshness is reported as `skipped` against
 * the locally stored latest draw.
 *
 * Fallback branching: numbers are always generated deterministically and the
 * response starts with `fallbackUsed: true`. If at least one combination is
 * produced, {@link explainWithAgent} is called; its `fallbackUsed` flag and
 * per-combination explanations are merged in, so a reachable, valid agent
 * downgrades `fallbackUsed` to `false` while an unavailable or invalid agent
 * leaves the deterministic explanations in place.
 *
 * @param body - Unvalidated request payload, parsed by `recommendationRequestSchema`.
 * @param opts - Optional overrides: `agentUrl` for the explanation service,
 *   `skipLiveSync` to bypass the provider sync, and `provider` to inject a
 *   `LotteryResultProvider` (defaults to {@link DhlotteryJsonProvider}).
 * @returns The recommendation response including numbers, freshness, feasibility,
 *   disclaimers, and (when available) agent explanations.
 * @throws {ZodError} If `body` fails `recommendationRequestSchema` validation.
 * @throws {Error} With `status: 400` if `targetDrawNo` is not later than the
 *   latest synced draw.
 */
export async function createRecommendations(
  body: unknown,
  opts: { agentUrl?: string; skipLiveSync?: boolean; provider?: LotteryResultProvider } = {},
): Promise<RecommendationResponse> {
  const req = recommendationRequestSchema.parse(body);
  const normalized = normalizeRequest(req);
  let freshness: DataFreshness = { latestSyncedDrawNo: 0, syncStatus: "skipped", syncErrorKind: null };

  if (!opts.skipLiveSync) {
    const provider = opts.provider ?? new DhlotteryJsonProvider();
    try {
      freshness = classifyFreshness(await syncDrawsBeforeServing(defaultStore, provider));
    } catch (err) {
      freshness = {
        latestSyncedDrawNo: await defaultStore.latestDrawNo(),
        syncStatus: "last-good",
        syncErrorKind: err instanceof DrawBackfillError ? err.code : err instanceof Error ? err.name : "UnknownError",
      };
    }
  }

  const draws = await defaultStore.listDraws();
  const latest = draws.at(-1)?.drawNo ?? 0;
  if (opts.skipLiveSync) freshness = { latestSyncedDrawNo: latest, syncStatus: "skipped", syncErrorKind: null };
  const targetDrawNo = normalized.targetDrawNo ?? latest + 1;
  if (targetDrawNo <= latest) {
    throw Object.assign(new Error("targetDrawNo must be later than the latest synced draw"), {
      status: 400,
    });
  }

  const requestId = randomUUID();
  const traceId = process.env.LANGFUSE_PUBLIC_KEY ? randomUUID() : null;
  const generated = generateRecommendations({
    luckyNumbers: normalized.luckyNumbers,
    count: normalized.count,
    historicalDraws: draws,
    targetDrawNo,
  });

  const base = {
    requestId,
    traceId,
    targetDrawNo,
    luckyNumbers: normalized.luckyNumbers,
    recommendations: generated.recommendations,
    fallbackUsed: true,
    freshness,
    feasibility: generated.feasibility,
    disclaimers: disclaimers(),
  } satisfies RecommendationResponse;

  if (generated.recommendations.length === 0) return base;

  const explanation = await explainWithAgent(
    {
      requestId,
      traceId,
      combinations: generated.recommendations.map(({ explanation: _e, tagNarration: _t, ...rest }) => rest),
      stats: { latestDrawNo: latest, historicalDraws: draws.length },
      luckyNumbers: normalized.luckyNumbers,
      targetDrawNo,
    },
    { agentUrl: opts.agentUrl },
  );

  const byId = new Map(explanation.perCombination.map((item) => [item.id, item]));
  return {
    ...base,
    fallbackUsed: explanation.fallbackUsed,
    recommendations: generated.recommendations.map((recommendation) => ({
      ...recommendation,
      ...(byId.get(recommendation.id) ?? {}),
    })),
  };
}

