import { fallbackExplanation } from "@lotto/core";
import {
  explainResponseSchema,
  type ExplainRequest,
  type ExplainResponse,
} from "@lotto/shared";

/**
 * Builds a deterministic explanation response from `@lotto/core` for every
 * requested combination, marked with `fallbackUsed: true`. Used whenever the
 * agent is unavailable, returns an invalid schema, omits/adds IDs, or itself
 * signals a fallback.
 *
 * @param request - The explanation request whose combinations are explained.
 * @param summary - Human-readable `analysisSummary` describing why the fallback
 *   path was taken.
 * @returns A complete `ExplainResponse` with one deterministic entry per
 *   requested combination.
 */
function fallbackResponse(request: ExplainRequest, summary: string): ExplainResponse {
  return {
    perCombination: request.combinations.map((combination) => ({
      id: combination.id,
      ...fallbackExplanation(combination.numbers, combination.tags, request.luckyNumbers),
    })),
    analysisSummary: summary,
    fallbackUsed: true,
  };
}

/**
 * Verifies that the agent response explains exactly the requested combinations —
 * the same set of IDs, with no duplicates, omissions, or extras on either side.
 *
 * @param request - The original explanation request.
 * @param response - The agent response to check against `request`.
 * @returns `true` only when the requested and returned ID sets match one-to-one.
 */
function hasExactExplanationCoverage(request: ExplainRequest, response: ExplainResponse) {
  if (response.perCombination.length !== request.combinations.length) return false;
  const expectedIds = request.combinations.map((combination) => combination.id);
  const actualIds = response.perCombination.map((item) => item.id);
  const expected = new Set(expectedIds);
  const actual = new Set(actualIds);
  if (expected.size !== expectedIds.length || actual.size !== actualIds.length) return false;
  return expected.size === actual.size && expectedIds.every((id) => actual.has(id));
}

/**
 * Requests LLM-authored explanations for a set of combinations from the agent's
 * `/explain` endpoint, degrading to deterministic explanations on any failure.
 *
 * The call is bounded by an `AbortController` timeout (`timeoutMs`, or
 * `AGENT_EXPLAIN_TIMEOUT_MS`, default 20s); the timer is always cleared in a
 * `finally` block.
 *
 * Fallback branching (in order):
 * - Non-2xx response, invalid JSON, or a schema that fails `explainResponseSchema`
 *   throws internally and is caught, yielding a deterministic fallback with an
 *   "Agent unavailable" summary.
 * - A valid response whose IDs don't exactly cover the request (see
 *   {@link hasExactExplanationCoverage}) yields a deterministic fallback with an
 *   "omitted or added recommendation IDs" summary.
 * - A valid, fully-covering response that itself sets `fallbackUsed: true` is
 *   replaced with deterministic explanations while preserving the agent's
 *   `analysisSummary`.
 * - Otherwise the agent's response is returned verbatim (`fallbackUsed: false`).
 *
 * This function never rejects: every failure mode resolves to a valid
 * `ExplainResponse`.
 *
 * @param request - The combinations, stats, lucky numbers, and target draw to explain.
 * @param opts - Optional `agentUrl` (defaults to `AGENT_URL` then
 *   `http://localhost:8000`) and `timeoutMs` overrides.
 * @returns An `ExplainResponse` — either the agent's explanations or a
 *   deterministic fallback, always covering exactly the requested combinations.
 */
export async function explainWithAgent(
  request: ExplainRequest,
  opts: { agentUrl?: string; timeoutMs?: number } = {},
): Promise<ExplainResponse> {
  const agentUrl = opts.agentUrl ?? process.env.AGENT_URL ?? "http://localhost:8000";
  const timeoutMs = opts.timeoutMs ?? Number(process.env.AGENT_EXPLAIN_TIMEOUT_MS ?? 20_000);
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeoutMs);

  try {
    const res = await fetch(`${agentUrl}/explain`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify(request),
      signal: controller.signal,
    });
    if (!res.ok) throw new Error(`agent ${res.status}`);

    const parsed = explainResponseSchema.safeParse(await res.json());
    if (!parsed.success) throw new Error("agent schema invalid");
    if (!hasExactExplanationCoverage(request, parsed.data)) {
      return fallbackResponse(
        request,
        "Agent response omitted or added recommendation IDs; deterministic fallback explanations used.",
      );
    }
    return parsed.data.fallbackUsed
      ? { ...fallbackResponse(request, parsed.data.analysisSummary), fallbackUsed: true }
      : parsed.data;
  } catch {
    return fallbackResponse(request, "Agent unavailable; deterministic fallback explanations used.");
  } finally {
    clearTimeout(timer);
  }
}
